class Solution:
    def completePrime(self, num: int) -> bool:
        def is_prime(v):
            if v < 2:
                return False
            if v < 4:
                return True
            if v % 2 == 0:
                return False
            i = 3
            while i * i <= v:
                if v % i == 0:
                    return False
                i += 2
            return True

        s = str(num)
        n = len(s)
        for i in range(1, n + 1):
            if not is_prime(int(s[:i])):
                return False
            if not is_prime(int(s[n - i:])):
                return False
        return True

