var completePrime = function(num) {
    function isPrime(v) {
        if (v < 2) return false;
        if (v < 4) return true;
        if (v % 2 === 0) return false;
        for (let i = 3; i * i <= v; i += 2) {
            if (v % i === 0) return false;
        }
        return true;
    }
    const s = String(num);
    const n = s.length;
    for (let i = 1; i <= n; i++) {
        if (!isPrime(parseInt(s.slice(0, i), 10))) return false;
        if (!isPrime(parseInt(s.slice(n - i), 10))) return false;
    }
    return true;
};
